#include <stdio.h>

int main(){
    int T, marks;
    if(scanf("%d", &T)!=1) return 0;
    while(T--){
        if(scanf("%d", &marks)!=1) break;
        if(marks>90) printf("A\n");
        else if(marks>70) printf("B\n");
        else if(marks>=40) printf("C\n");
        else printf("F\n");
    }
    return 0;
}

