code.Java:
import java.io.*;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if(line==null || line.isEmpty()) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for(int i=0;i<T;i++){
            int marks = Integer.parseInt(br.readLine().trim());
            if(marks>90) sb.append('A');
            else if(marks>70) sb.append('B');
            else if(marks>=40) sb.append('C');
            else sb.append('F');
            sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    T = int(data[0])
    out = []
    idx = 1
    for _ in range(T):
        marks = int(data[idx])
        idx += 1
        if marks > 90:
            out.append('A')
        elif marks > 70:
            out.append('B')
        elif marks >= 40:
            out.append('C')
        else:
            out.append('F')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

